'use client';
import { useEffect, useRef, useState } from 'react';

interface ShimmerColor {
  r: number;
  g: number;
  b: number;
}

function computeShimmerColors(
  totalWidth: number,
  shimmerPos: number,
  pulse: number
): ShimmerColor[] {
  const shimmerRadius = Math.floor(totalWidth / 2.5);
  const colors: ShimmerColor[] = [];

  for (let i = 0; i < totalWidth; i++) {
    const dist = Math.abs(i - shimmerPos);
    const shimmer = Math.max(0, 1 - dist / shimmerRadius);

    const baseR = 36 + (i / totalWidth) * 10;
    const baseG = 20 + (i / totalWidth) * 8;
    const baseB = 100 + (i / totalWidth) * 20;

    const r = baseR + (200 - baseR) * shimmer * 0.6;
    const g = baseG + (165 - baseG) * shimmer * 0.6;
    const b = baseB + (255 - baseB) * shimmer * 0.7;

    const p = 1 + pulse * 0.06;
    colors.push({
      r: Math.min(255, Math.round(r * p)),
      g: Math.min(255, Math.round(g * p)),
      b: Math.min(255, Math.round(b * p)),
    });
  }

  return colors;
}

interface ShimmerLoaderProps {
  labels: string[];
  icons: string[];
  duration: number;
  tokenTarget?: number;
  showPercent?: boolean;
  /** Font size in px. Default 14. Bar height scales automatically. */
  fontSize?: number;
  /** Vertical padding inside each cell, in px. Default 4. */
  paddingY?: number;
  /** Blank monospace cells on each side of the label. Default 2. */
  cellPadding?: number;
  /** Tailwind class for the character text color. */
  textClassName?: string;
  onComplete: () => void;
}

export function ShimmerLoader({
  labels,
  icons,
  duration,
  tokenTarget,
  showPercent = true,
  fontSize = 14,
  paddingY = 4,
  cellPadding = 2,
  textClassName = 'text-purple-200/90',
  onComplete,
}: ShimmerLoaderProps) {
  const cellsRef = useRef<(HTMLSpanElement | null)[]>([]);
  const frameRef = useRef(0);
  const rafRef = useRef<number>(0);
  const doneRef = useRef(false);
  const lastFrameTimeRef = useRef(0);

  const [icon, setIcon] = useState(icons[0]);
  const [iconColor, setIconColor] = useState<[number, number, number]>(
    [160, 110, 255],
  );
  const [tokens, setTokens] = useState('0.0');

  const showTokens = tokenTarget !== undefined;

  const percentBudget = showPercent ? ' 100%'.length : 0;
  const longestInner = Math.max(
    ...labels.map((l) => (' ' + l + ' ').length + percentBudget)
  );
  const barWidth = longestInner + cellPadding * 2;

  useEffect(() => {
    const fps = 40;
    const frameMs = 1000 / fps;
    const totalFrames = Math.round(duration / frameMs);
    const sliceFrames = Math.floor(totalFrames / labels.length);
    const shimmerRadius = Math.floor(barWidth / 2.5);
    const shimmerCycleLen = barWidth + shimmerRadius * 2;

    function buildContent(label: string, pct: number): string[] {
      const percentStr = showPercent ? ' ' + pct + '%' : '';
      const rawInner = ' ' + label + percentStr + ' ';
      const inner = rawInner.padEnd(longestInner);
      const padStr = ' '.repeat(cellPadding);
      return (padStr + inner + padStr).split('');
    }

    function draw(ts: number) {
      if (ts - lastFrameTimeRef.current < frameMs - 1) {
        rafRef.current = requestAnimationFrame(draw);
        return;
      }
      lastFrameTimeRef.current = ts;

      const f = frameRef.current;
      const progress = Math.min(f / totalFrames, 1);
      const pct = Math.round(progress * 100);
      const shimmerPos = ((f * 1.2) % shimmerCycleLen) - shimmerRadius;
      const pulse = Math.sin(f * 0.18);
      const done = f >= totalFrames;
      const labelIdx = Math.min(Math.floor(f / sliceFrames), labels.length - 1);
      const currentLabel = done ? labels[labels.length - 1] : labels[labelIdx];
      const currentIcon = done ? '⌘' : icons[Math.floor(f / 5) % icons.length];
      const ic = done ? 200 : Math.round(160 + pulse * 25);

      setIcon(currentIcon);
      setIconColor([ic, 110, 255]);
      if (showTokens) {
        setTokens((progress * (tokenTarget as number)).toFixed(1));
      }

      const content = buildContent(currentLabel, pct);
      const colors = computeShimmerColors(barWidth, shimmerPos, pulse);

      for (let i = 0; i < barWidth; i++) {
        const cell = cellsRef.current[i];
        if (!cell) continue;
        const { r, g, b } = colors[i];
        cell.style.backgroundColor = `rgb(${r},${g},${b})`;
        const ch = content[i] ?? ' ';
        if (cell.textContent !== ch) cell.textContent = ch;
      }

      frameRef.current = f + 1;
      if (!done) {
        rafRef.current = requestAnimationFrame(draw);
      } else if (!doneRef.current) {
        doneRef.current = true;
        onComplete();
      }
    }

    rafRef.current = requestAnimationFrame(draw);
    return () => cancelAnimationFrame(rafRef.current);
  }, []);

  const [ir, ig, ib] = iconColor;

  return (
    <div className='inline-flex items-center gap-2' style={{ fontSize }}>
      <span
        className='leading-none'
        style={{ color: `rgb(${ir},${ig},${ib})`, fontSize: fontSize * 1.15 }}
      >
        {icon}
      </span>

      <div
        className='inline-flex font-mono leading-none whitespace-pre'
        style={{ fontSize }}
      >
        {Array.from({ length: barWidth }).map((_, i) => (
          <span
            key={i}
            ref={(el) => {
              cellsRef.current[i] = el;
            }}
            className={`inline-block whitespace-pre ${textClassName}`}
            style={{ padding: `${paddingY}px 0` }}
          >
            {' '}
          </span>
        ))}
      </div>

      {showTokens && (
        <span
          className='text-purple-700/70 tabular-nums'
          style={{ fontSize: fontSize * 0.85 }}
        >
          {tokens}k
        </span>
      )}
    </div>
  );
}

'use client';
import { Play } from 'lucide-react';
import { useEffect, useRef, useState } from 'react';

interface TypeWritterProps {
  text: string;
  charDelay?: number;
  onComplete: () => void;
}

export function TypeWritter({
  text,
  charDelay = 55,
  onComplete,
}: TypeWritterProps) {
  const [displayed, setDisplayed] = useState('');
  const doneRef = useRef(false);

  useEffect(() => {
    let i = 0;
    let cancelled = false;

    function typeNext() {
      if (cancelled) return;
      if (i >= text.length) {
        if (!doneRef.current) {
          doneRef.current = true;
          onComplete();
        }
        return;
      }
      setDisplayed(text.slice(0, i + 1));
      i++;
      setTimeout(typeNext, charDelay);
    }

    typeNext();
    return () => {
      cancelled = true;
    };
  }, []);

  return (
    <div className='flex items-center gap-2'>
      <span className='text-sm text-purple-500'>
        <Play className='w-3 h-3 fill-purple-500' />
      </span>
      <span className='text-sm font-bold tracking-[0.2px] text-purple-200'>
        {displayed}
        <span className='ml-0.5 inline-block h-[1em] w-0.5 align-text-bottom bg-purple-200/70 animate-[blink_1s_step-end_infinite]' />
      </span>
    </div>
  );
}

'use client';
import { ShimmerLoader } from '@/components/ui/shimmer-loader';
import { TypeWritter } from '@/components/ui/typing-writter';
import { useEffect, useRef, useState, useCallback } from 'react';

type Phase =
  | { type: 'divider' }
  | {
      type: 'bar';
      labels: string[];
      icons: string[];
      duration: number;
      tokenTarget?: number;
      showPercent?: boolean;
    }
  | { type: 'lines'; lines: string[] }
  | { type: 'message'; text: string };

export interface IntroSequenceProps {
  onComplete?: () => void;
  className?: string;
  style?: React.CSSProperties;
}

interface RenderedItem {
  id: string;
  phase: Phase;
  lineIndex?: number;
}

function Divider() {
  return (
    <div
      style={{
        color: 'rgba(210,190,255,0.2)',
        fontSize: 13,
        letterSpacing: '1px',
        fontFamily: "'Cascadia Code', 'Fira Code', 'Consolas', monospace",
      }}
    >
      {'─'.repeat(44)}
    </div>
  );
}

const SEQUENCE: Phase[] = [
  { type: 'divider' },
  {
    type: 'bar',
    labels: ['Scanning…', 'Analysing…', 'Detecting…', 'Profiling…'],
    icons: ['✦', '◆', '✶', '❋', '✸'],
    duration: 3000,
    tokenTarget: 0.6,
    showPercent: true,
  },
  {
    type: 'lines',
    lines: ['New Role Detected', 'New Team Detected', 'New Challenges'],
  },
  { type: 'divider' },
  {
    type: 'bar',
    labels: ['Booting…', 'Loading…', 'Preparing…', 'Initializing…'],
    icons: ['✦', '◆', '✶', '❋', '✸'],
    duration: 3000,
    showPercent: false,
  },
  { type: 'message', text: "Let's build something great 🚀" },
  { type: 'divider' },
  {
    type: 'bar',
    labels: ['Syncing…', 'Configuring…', 'Setting up…', 'Onboarding…'],
    icons: ['◈', '◉', '⬡', '⬢', '◍'],
    duration: 3000,
    tokenTarget: 0.8,
    showPercent: false,
  },
];

export function NewIntroSequence({
  onComplete,
  className,
  style,
}: IntroSequenceProps) {
  const [items, setItems] = useState<RenderedItem[]>([]);
  const phaseRef = useRef(0);
  const lineRef = useRef(0);
  const completedRef = useRef(false);

  const advance = useCallback(() => {
    const phase = SEQUENCE[phaseRef.current];
    if (!phase) {
      if (!completedRef.current) {
        completedRef.current = true;
        onComplete?.();
      }
      return;
    }

    if (phase.type === 'divider') {
      setItems((prev) => [
        ...prev,
        { id: `divider-${phaseRef.current}`, phase },
      ]);
      phaseRef.current++;
      setTimeout(advance, 80);
      return;
    }

    if (phase.type === 'bar') {
      setItems((prev) => [...prev, { id: `bar-${phaseRef.current}`, phase }]);
      phaseRef.current++;
      return;
    }

    if (phase.type === 'lines') {
      lineRef.current = 0;
      phaseRef.current++;
      typeNextLine(phase.lines);
      return;
    }

    if (phase.type === 'message') {
      setItems((prev) => [...prev, { id: `msg-${phaseRef.current}`, phase }]);
      phaseRef.current++;
      setTimeout(advance, 400);
      return;
    }
  }, [onComplete]);

  function typeNextLine(lines: string[]) {
    const idx = lineRef.current;
    if (idx >= lines.length) {
      setTimeout(advance, 200);
      return;
    }
    setItems((prev) => [
      ...prev,
      {
        id: `line-${phaseRef.current - 1}-${idx}`,
        phase: { type: 'lines', lines },
        lineIndex: idx,
      },
    ]);
    lineRef.current++;
  }

  useEffect(() => {
    setTimeout(advance, 300);
  }, []);

  return (
    <>
      <style>{`@keyframes blink { 0%,100%{opacity:1} 50%{opacity:0} }`}</style>
      <div
        className={className}
        style={{
          background: '#0f0e17',
          padding: '24px 28px',
          display: 'flex',
          flexDirection: 'column',
          gap: 10,
          fontFamily: "'Cascadia Code', 'Fira Code', 'Consolas', monospace",
          minWidth: 520,
          ...style,
        }}
      >
        {items.map((item) => {
          const { id, phase } = item;

          if (phase.type === 'divider') return <Divider key={id} />;

          if (phase.type === 'bar') {
            return (
              <ShimmerLoader
                key={id}
                labels={phase.labels}
                icons={phase.icons}
                duration={phase.duration}
                tokenTarget={phase.tokenTarget}
                showPercent={phase.showPercent}
                onComplete={() => {
                  setTimeout(advance, 150);
                }}
              />
            );
          }

          if (phase.type === 'lines' && item.lineIndex !== undefined) {
            const isLast = item.lineIndex === phase.lines.length - 1;
            return (
              <TypeWritter
                key={id}
                text={phase.lines[item.lineIndex]}
                onComplete={() => {
                  setTimeout(() => typeNextLine(phase.lines), isLast ? 0 : 200);
                }}
              />
            );
          }

          if (phase.type === 'message') {
            return (
              <div
                key={id}
                style={{
                  color: 'rgb(160,130,255)',
                  fontWeight: 700,
                  fontSize: 14,
                  paddingLeft: 4,
                }}
              >
                {phase.text}
              </div>
            );
          }

          return null;
        })}
      </div>
    </>
  );
}
